diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..1953e06d513e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2719,6 +2719,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   // Note: We don't generate the inverse max/min, just create the 'not' of
   // it and let other folds do the rest.
   if (match(Op0, m_Not(m_Value(X))) &&
+
       match(Op1, m_c_MaxOrMin(m_Specific(Op0), m_Value(Y))) &&
       !Op0->hasNUsesOrMore(3) && isFreeToInvert(Y, Y->hasOneUse())) {
     Value *Not = Builder.CreateNot(Op1);
@@ -2731,6 +2732,22 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     return BinaryOperator::CreateSub(X, Not);
   }

+  // Simplify sub(smin(X+1, Y), smin(X, Y)) to (X < Y) ? 1 : 0
+  Value *X0, *Y0;
+  if (match(Op0, m_OneUse(m_c_SMin(m_Add(m_Value(X0), m_One()), m_Value(Y0)))) &&
+      match(Op1, m_OneUse(m_c_SMin(m_Specific(X0), m_Specific(Y0))))) {
+    Value *Cmp = Builder.CreateICmpSLT(X0, Y0);
+    return SelectInst::Create(Cmp, ConstantInt::get(I.getType(), 1),
+                              ConstantInt::get(I.getType(), 0));
+  }
+  // Also handle the symmetric case: sub(smin(X, Y), smin(X+1, Y)) to (X < Y) ? -1 : 0
+  if (match(Op0, m_OneUse(m_c_SMin(m_Value(X0), m_Value(Y0)))) &&
+      match(Op1, m_OneUse(m_c_SMin(m_Add(m_Specific(X0), m_One()), m_Specific(Y0))))) {
+    Value *Cmp = Builder.CreateICmpSLT(X0, Y0);
+    return SelectInst::Create(Cmp, ConstantInt::get(I.getType(), -1),
+                              ConstantInt::get(I.getType(), 0));
+  }
+
   // Optimize pointer differences into the same array into a size.  Consider:
   //  &A[10] - &A[0]: we should compile this to "10".
   Value *LHSOp, *RHSOp;
@@ -2872,15 +2889,15 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Instruction *Res = foldBinOpOfSelectAndCastOfSelectCondition(I))
     return Res;

-  // (sub (sext (add nsw (X, Y)), sext (X))) --> (sext (Y))
+  // (sub (sext (add nsw (X, Y))), sext (X))) --> (sext (Y))
   if (match(Op1, m_SExtLike(m_Value(X))) &&
       match(Op0, m_SExtLike(m_c_NSWAdd(m_Specific(X), m_Value(Y))))) {
     Value *SExtY = Builder.CreateSExt(Y, I.getType());
     return replaceInstUsesWith(I, SExtY);
   }

-  // (sub[ nsw] (sext (add nsw (X, Y)), sext (add nsw (X, Z)))) -->
-  // --> (sub[ nsw] (sext (Y), sext (Z)))
+  // (sub[ nsw] (sext (add nsw (X, Y))), sext (add nsw (X, Z)))) -->
+  // --> (sub[ nsw] (sext (Y)), sext (Z)))
   {
     Value *Z, *Add0, *Add1;
     if (match(Op0, m_SExtLike(m_Value(Add0))) &&
@@ -2920,6 +2937,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
 /// This eliminates floating-point negation in either 'fneg(X)' or
 /// 'fsub(-0.0, X)' form by combining into a constant operand.
 static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {

